    acb_cnd_lc_iogb.setValue("O")

    // for test data
    //ed_cnd_ed_sdate.setValue("201501");

    ds_close.set("closeDt", ed_cnd_ed_sdate.getValue());
    $c.sbm.execute(sbm_retrieve);
};

