//-------------------------------
// search 버튼 클릭시
//-------------------------------
/**
 * @method
 * @name f_retrueveResults
 * @description Search 버튼 클릭시 미확정 실적을 조회한다.
 * @param {string} e desc
 * @hidden N
 * @exception 
 * @example ${example}
 */ 
scwin.f_retrueveResults = async function (e) {
    ds_condition.set("kcomcd", "DBEX");
    ds_condition.set("yymmSeq", ds_closeResult.getCellData(ds_closeResult.getRowPosition(), "closeCnt"));

    // 필수항목 체크
    let ret = await $c.gus.cfValidate([tbl_searchCondition, tbl_searchCondition2])
    if (!ret) {
        return;
    }

    if ((ed_cnd_ed_rslDtFrom.getValue() == "" && ed_cnd_ed_rslDtTo.getValue() != "")
        || (ed_cnd_ed_rslDtFrom.getValue() != "" && ed_cnd_ed_rslDtTo.getValue() == "")) {
        $c.win.alert("실적일 조회시는 시작일과 종료일 모두 입력되어야 합니다.");
        return false;
    }

    if (!$c.gus.cfIsAfterDate(ed_cnd_ed_rslDtFrom.getValue(), ed_cnd_ed_rslDtTo.getValue())) {
        $c.win.alert("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ed_cnd_ed_rslDtFrom.focus();
        return false;
    }
    //실적일자와 result가 같아야함
    if (ed_cnd_ed_rslDtFrom.getValue() != "" || ed_cnd_ed_rslDtTo.getValue() != "") {
        if (ed_cnd_ed_sdate.getValue() != ed_cnd_ed_rslDtFrom.getValue().substring(0, 6) || ed_cnd_ed_sdate.getValue() != ed_cnd_ed_rslDtTo.getValue().substring(0, 6)) {
            $c.win.alert("실적년월은 Result Date와 동일해야 합니다. ");
            ed_cnd_ed_sdate.focus();
            return false;
        }
    }

    //var diffObj = cfDifferBetween(cnd_ed_rslDtFrom.getValue(), cnd_ed_rslDtTo.getValue(),"YYYYMMDD");

    // 조회 기간이 1달 이상인경우 확인
    //if(diffObj.year > 0 || diffObj.month > 0){
    //if(!cfConfirmMsg(["조회기간 이 1개월이 넘습니다.조회하시겠습니까?"])){
    //cnd_ed_rslDtTo.Focus();
    //return false;
    //}
    //} 	

    var odrNo = "";
    var odrNo2 = "";
    var seaAir = acb_cnd_lc_jobgb.getValue();
    var ioGb = acb_cnd_lc_iogb.getValue();

    if (seaAir != "D") {	// Container+Bulk 인 경우
        odrNo = "L" + seaAir;
        if (ioGb == "O") {
            odrNo = odrNo + "E";
        } else if (ioGb == "I") {
            odrNo = odrNo + "I";
        } else {
        }
    } else {				// Container+Bulk 가 아닌 경우
        odrNo = "LC";
        odrNo2 = "LB";
        if (ioGb == "O") {
            odrNo = odrNo + "E";
            odrNo2 = odrNo2 + "E";
        } else if (ioGb == "I") {
            odrNo = odrNo + "I";
            odrNo2 = odrNo2 + "I";
        } else {
        }
    }
    ds_condition.set("odrNo", odrNo);
    ds_condition.set("odrNo2", odrNo2);

    $c.sbm.execute(sbm_retrieveResults)

    //이력조회여부 체크시에만 이력조회함
    if (cbx_histYn.getValue() == "1") {
        $c.sbm.execute(sbm_retrieveResultsHist)
    }

};

//-------------------------------------------------------------------------
// 오즈화면
//-------------------------------------------------------------------------
/**
 * @method
 * @name f_Print
 * @description 오즈 리포트를 출력하기 위해 파라미터를 셋팅하고 오즈 팝업을 띄운다.
 * @param {string} e desc
 * @hidden N
 * @exception 
 * @example ${example}
 */ 
scwin.f_Print = function (e) {

    let seaair = (acb_cnd_lc_jobgb.getValue() ?? "").trim();
    if((scwin.hid_seq ?? "") == ""){
        $c.win.alert("Closing 차수를 선택 하세요.");
        return;
    }

    let data = undefined;
    switch (seaair) {
        case "C": // Container
            data = {
                odiName: 'pe_103_01_01',
                reportName: '/il/pfm/pe_103_01_01_cntr.ozr',
                odiParam: {
                    KCOMCD: scwin.hid_kcomcd,
                    IOGB: acb_cnd_lc_iogb.getValue(),
                    SEAAIR: acb_cnd_lc_jobgb.getValue(),
                    YYMM: ed_cnd_ed_sdate.getValue().trim(),
                    YYMM_SEQ: scwin.hid_seq,
                    DEPT: ed_dept.getValue().trim(),
                    INPUT: scwin.hid_input,
                    INC_YN: chb_incYn.getValue() == "1" ? "N" : "Y"
                },
                viewerParam: {  // OZ 뷰어에 대한 설정
                    useprogressbar: false,
					zoom: 100,
                    mode: 'print'
                },
                formParam: {   // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
                }
            };
            break;
        case "B": // Bulk
            data = {
                odiName: 'pe_103_01_01',
                reportName: '/il/pfm/pe_103_01_01_bulk.ozr',
                odiParam: {
                    KCOMCD: scwin.hid_kcomcd,
                    IOGB: acb_cnd_lc_iogb.getValue(),
                    SEAAIR: acb_cnd_lc_jobgb.getValue(),
                    YYMM: ed_cnd_ed_sdate.getValue().trim(),
                    YYMM_SEQ: scwin.hid_seq,
                    DEPT: ed_dept.getValue().trim(),
                    INPUT: scwin.hid_input,
                    INC_YN: chb_incYn.getValue() == "1" ? "N" : "Y"
                },
                viewerParam: {  // OZ 뷰어에 대한 설정
                    useprogressbar: false,
					zoom: 100,
                    mode: 'print'
                },
                formParam: {   // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
                }
            };
            break;
        case "A": // Air
            data = {
                odiName: 'pe_103_01_01',
                reportName: '/il/pfm/pe_103_01_01.ozr',
                odiParam: {
                    KCOMCD: scwin.hid_kcomcd,
                    IOGB: acb_cnd_lc_iogb.getValue(),
                    SEAAIR: acb_cnd_lc_jobgb.getValue(),
                    YYMM: ed_cnd_ed_sdate.getValue().trim(),
                    YYMM_SEQ: scwin.hid_seq,
                    DEPT: ed_dept.getValue().trim(),
                    INPUT: scwin.hid_input,
                    INC_YN: chb_incYn.getValue() == "1" ? "N" : "Y"
                },
                viewerParam: {  // OZ 뷰어에 대한 설정
                    useprogressbar: false,
					zoom: 90,
                    mode: 'print'
                },
                formParam: {   // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
                }
            };
            break;
        case "D": // Container+Bulk
            data = {
                odiName: 'pe_103_01_01',
                reportName: '/il/pfm/pe_103_01_01_cntr.ozr',
                odiParam: {
                    KCOMCD: scwin.hid_kcomcd,
                    IOGB: acb_cnd_lc_iogb.getValue(),
                    SEAAIR: acb_cnd_lc_jobgb.getValue(),
                    YYMM: ed_cnd_ed_sdate.getValue().trim(),
                    YYMM_SEQ: scwin.hid_seq,
                    DEPT: ed_dept.getValue().trim(),
                    INPUT: scwin.hid_input,
                    INC_YN: chb_incYn.getValue() == "1" ? "N" : "Y"
                },
                viewerParam: {  // OZ 뷰어에 대한 설정
                    useprogressbar: false,
					zoom: 90,
                    mode: 'print'
                },
                formParam: {   // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
                }
            };
            break;
    }

    if (data != undefined) {
        scwin.openOzPopup(data);
    }
};


/**
 * @method
 * @name openOzPopup
 * @description 오즈리포트 화면을 띄운다
 * @param {string} data desc
 * @hidden N
 * @exception ㅆ
 * @example ${example}
 */ 
scwin.openOzPopup = async function (data) {
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };
    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

//-------------------------------------------------------------------------
// 저장(Close)
//-------------------------------------------------------------------------
/**
 * @method
 * @name f_Close
 * @description Closing 처리하여 저장한다.
 * @param {string} e desc
 * @hidden N
 * @exception 
 * @example ${example}
 */ 
scwin.f_Close = async function (e) {
    let confirm = await $c.win.confirm($c.data.getMessage(E_MSG_CM_CRM_001));
	if (confirm) {
        $c.sbm.execute(sbm_save)
    }
};

